css:
.loader {color: var(--loader-color, #0f766e);
  --loader-secondary-color: #5eead4;
  --loader-bg: #ffffff;
   height: 66px;
   aspect-ratio: 1;
   display: grid;
}
.loader:before, .loader:after  {
  content: "";
   --c:no-repeat linear-gradient(currentColor 0 0);
   background: var(--c), var(--c);
   background-size: 25% 50%;
   animation: l5 1.5s infinite linear;
}
.loader:after  {
  transform: scale(-1);
}
@keyframes l5  {
  0%, 5% {background-position:33.4% 100%,66.6% 100%}
25% {background-position:33.4% 100%,100% 0}
50% {background-position:0 0,100% 0}
75% {background-position:0 0,66.6% 100%}
95%, 100% {background-position:33.4% 100%,66.6% 100%}
}
